parts.text:
Welcome to the HR Intake Assistant! I see you want to initiate a **Promotion** for an employee.

I have successfully pulled the details for **Alex Mercer (EMP1001)**. Please review the current details and specify the parameters for the new promotion.

<a2ui-json>
{
  "version": "v0.9",
  "createSurface": {
    "surfaceId": "hr_intake_promotion_form",
    "catalogId": "https://a2ui.org/specification/v0_9/basic_catalog.json",
    "theme": {
      "agentDisplayName": "HR Intake Assistant"
    }
  }
}
</a2ui-json>
<a2ui-json>
{
  "version": "v0.9",
  "updateDataModel": {
    "surfaceId": "hr_intake_promotion_form",
    "value": {
      "employee": {
        "id": "EMP1001",
        "name": "Alex Mercer",
        "currentJobTitle": "Senior Game Advisor",
        "currentJobCode": "SGA01",
        "currentPayRate": 16.50
      },
      "form": {
        "changeType": "Promotion",
        "newJobCode": null,
        "newPayRate": null,
        "effectiveDate": "",
        "justification": null
      },
      "jobsList": [
        {
          "label": "Assistant Store Leader (ASL01)",
          "value": "ASL01"
        },
        {
          "label": "Store Leader (SL01)",
          "value": "SL01"
        }
      ]
    }
  }
}
</a2ui-json>
<a2ui-json>
{
  "version": "v0.9",
  "updateComponents": {
    "surfaceId": "hr_intake_promotion_form",
    "components": [
      {
        "id": "root",
        "component": "Column",
        "children": [
          "empSummaryCard",
          "formCol"
        ]
      },
      {
        "id": "empSummaryCard",
        "component": "Card",
        "child": "summaryCol"
      },
      {
        "id": "summaryCol",
        "component": "Column",
        "children": [
          "nameText",
          "currentJobText",
          "currentPayText"
        ]
      },
      {
        "id": "nameText",
        "component": "Text",
        "variant": "h3",
        "text": {
          "call": "formatString",
          "args": {
            "value": "Promotion for ${/employee/name} (EMP1001)"
          }
        }
      },
      {
        "id": "currentJobText",
        "component": "Text",
        "variant": "body",
        "text": {
          "call": "formatString",
          "args": {
            "value": "Current Job: ${/employee/currentJobTitle} (${/employee/currentJobCode})"
          }
        }
      },
      {
        "id": "currentPayText",
        "component": "Text",
        "variant": "body",
        "text": {
          "call": "formatString",
          "args": {
            "value": "Current Hourly Pay: ${formatCurrency(value:/employee/currentPayRate, currency:'USD')}"
          }
        }
      },
      {
        "id": "formCol",
        "component": "Column",
        "children": [
          "jobPicker",
          "payField",
          "dateInput",
          "submitButton"
        ]
      },
      {
        "id": "jobPicker",
        "component": "ChoicePicker",
        "label": "1. Select New Job Title",
        "variant": "mutuallyExclusive",
        "options": {
          "path": "/jobsList"
        },
        "value": {
          "path": "/form/newJobCode"
        },
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/form/newJobCode"
                }
              }
            },
            "message": "The new job title is required for a promotion."
          }
        ]
      },
      {
        "id": "payField",
        "component": "TextField",
        "label": "2. Proposed New Hourly Pay Rate ($)",
        "variant": "number",
        "value": {
          "path": "/form/newPayRate"
        },
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/form/newPayRate"
                }
              }
            },
            "message": "A proposed new pay rate is required."
          },
          {
            "condition": {
              "call": "numeric",
              "args": {
                "value": {
                  "path": "/form/newPayRate"
                },
                "min": 16.51
              }
            },
            "message": "Proposed pay must be a raise (greater than the current $16.50/hr)."
          }
        ]
      },
      {
        "id": "dateInput",
        "component": "DateTimeInput",
        "label": "3. Effective Date (YYYY-MM-DD)",
        "enableDate": true,
        "value": {
          "path": "/form/effectiveDate"
        },
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/form/effectiveDate"
                }
              }
            },
            "message": "An effective date is required."
          }
        ]
      },
      {
        "id": "submitButton",
        "component": "Button",
        "child": "submitText",
        "variant": "primary",
        "action": {
          "event": {
            "name": "hr_intake_submit_promotion",
            "context": {
              "employeeId": {
                "path": "/employee/id"
              },
              "currentPayRate": {
                "path": "/employee/currentPayRate"
              },
              "newJobCode": {
                "path": "/form/newJobCode"
              },
              "newPayRate": {
                "path": "/form/newPayRate"
              },
              "effectiveDate": {
                "path": "/form/effectiveDate"
              }
            }
          }
        }
      },
      {
        "id": "submitText",
        "component": "Text",
        "text": "Review Promotion & Policy Check"
      }
    ]
  }
}
</a2ui-json>

Please fill out the form above with the new job title, the proposed hourly pay rate, and the effective date for Alex Mercer's promotion. Once complete, I will run a policy check on the inputs.

