              "type": "string",
              "description": "Defines the alignment of children along the cross axis.",
              "enum": [
                "start",
                "center",
                "end",
                "stretch"
              ],
              "default": "stretch"
            }
          },
          "required": [
            "component",
            "children"
          ]
        }
      ],
      "unevaluatedProperties": false
    },
    "Card": {
