          },
          "required": [
            "surfaceId"
          ],
          "additionalProperties": false
        }
      },
      "required": [
        "updateDataModel",
        "version"
      ],
      "additionalProperties": false
    },
    "DeleteSurfaceMessage": {
      "type": "object",
      "properties": {
